// @hoge1e3/ref-input
import {get,set,change} from "@hoge1e3/ref";
import EventManager from "@hoge1e3/dom-mutable-events";
const evm=new EventManager();
const refevs=new WeakMap();//ref=>Set<id>
function setVal(dom,val) {
  if (dom.type==="checkbox"){
    dom.checked=!!val;
  } else {
    dom.value=val;
  }
}
function getVal(dom) {
  if (dom.type==="checkbox"){
      return !!dom.checked; 
  } else {
    return dom.value;
  }
}
export function refInput(r,dom){
  const id=dom.getAttribute("id");
  if(!id)throw new Error(" refInput requires id");
  setVal(dom, get(r));
  evm.add(dom,"input",function (){
    set(r, getVal(this));
  });
  let refev=refevs.get(r);
  if(!refev){
    refev=new Set();
    refevs.set(r,refev);
  }
  if(!refev.has(id)){
    change(r,({val})=>{
      const t=document.getElementById(id);
      setVal(t,val);
    });
    refev.add(id);
  }
  return dom;
}
